(1, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_0', 'Coin-Afrique', '26 000 000 CFA', 26000000, 'Lomé, Togo', 'Terrain à Agoè- Vakpossito. A vendre 26 millions très bon terrain en vente un (01) lot clôturé sis à agoè- vakpossito proche du carrefour fish bien positionné pour tout projet immobilier. document : titre foncier prix de vente d\'urgence : 26 millions.', '[\"https://coinafrique-ads-photos.s3.amazonaws.com/photos/6df05fb3-89f.png\", \"https://images.coinafrique.com/thumb_4081859_uploaded_image1_1675665921.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(2, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_1', 'Coin-Afrique', '5 000 000 CFA', 5000000, 'Tsévié - Agbélouve, Lomé, Togo', 'Terrain 5 lots 2971 m² à Tsévié - Agbélouve. Une parcelle stratégique sur 05 lots collés soit (2971 m²) située en trois angles de rue. Très bien positionnée pour tout type de projet immobilier. Position : Tsévié - Agbélouve, à 80 m du goudron. Coût : 5 MILLIONS / lot légèrement discutable. Acte de propriété : Plan visé OTR (Titre foncier en cours).', '[]', 'https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(3, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_2', 'Coin-Afrique', '4 200 000 CFA', 4200000, 'Lomé, Togo', 'Terrain 1/2 lot à Akébé (Akepe) situé à 800 m du goudron de contournement, bénéficiant d’une voie de 18 m. Superficie de 300 m². À vendre en demi‑lot. Documents disponibles : plan OTR + avis favorable. Prix indiqué : 4 200 000 francs CFA.', '[\"https://images.coinafrique.com/thumb_5739441_uploaded_image1_1769274034.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(4, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_3', 'Coin-Afrique', '100 000 000 CFA', 100000000, 'Ahanoukopé marché, Lomé, Togo', 'Terrain 1 lot 625 m² à Ahanoukopé marché. Parcelle bien carrée de 1 lot (625 m²), située à 20 m du goudron (2ᵉ lot). Emplacement stratégique et idéal pour tout projet immobilier ou commercial. Superficie : 625 m². Document : titre foncier personnel. Prix de vente : 100 millions CFA (discutables).', '[\"https://images.coinafrique.com/thumb_5722723_uploaded_image1_1768490644.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(5, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_4', 'Coin-Afrique', '22 500 000 CFA', 22500000, 'Lomé, Togo', 'Terrain de 2400 m² composé de 04 (quatre) lots collés en angle, situés au bord du goudron de contournement à Noepe (après le péage). Chaque lot est proposé à 22 500 000 F CFA, prix légèrement négociable. Le titre foncier est personnel.', '[\"https://images.coinafrique.com/thumb_5720852_uploaded_image1_1768400260.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-4-lots-colles-au-bord-de-goudron-de-contournement-a-noepe-5720852', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-4-lots-colles-au-bord-de-goudron-de-contournement-a-noepe-5720852\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-4-lots-colles-au-bord-de-goudron-de-contournement-a-noepe-5720852\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-4-lots-colles-au-bord-de-goudron-de-contournement-a-noepe-5720852\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(6, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_5', 'Coin-Afrique', '35 000 000 CFA', 35000000, 'Lomé, Togo', 'Très bon terrain au bord du goudron a vendre un terrain de surface de 200m² soit (10m/20m) à déduire d\'une maison face goudron a agoè démakpoè document : plan visé prix immobilier : 35 millions visite possible', '[\"https://images.coinafrique.com/thumb_5724973_uploaded_image1_1768591896.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-200m-demakpoe-5724973', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-demakpoe-5724973\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-demakpoe-5724973\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-demakpoe-5724973\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(7, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_6', 'Coin-Afrique', '40 000 000 CFA', 40000000, 'Lomé, Togo', 'Terrain a vendre a klobatemé. Superficie: 1200 m². 2 lots collés disponibles au bord du goudron sur un site initial de 06 lots, situé à 1 km de l\'échangeur de Kégué en allant vers Djagblé. Prix : 40 millions le tout, dernier prix. Document : titre foncier sur 06 lots collés.', '[\"https://images.coinafrique.com/thumb_5721203_uploaded_image1_1768412754.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-klobateme-5721203', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-klobateme-5721203\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-klobateme-5721203\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-klobateme-5721203\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(8, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_7', 'Coin-Afrique', '12 000 000 CFA', 12000000, 'Lomé, Togo', 'A vendre une maison de 2 chambres salon wc douche cuisine interne + une boutique et une pièce interne inachevée construction sur suart de lot. Situation géographique : Legbassito : Dangbessito non loin du supérette coun de chute, à 200 m de goudron. Surface : 159 m². Document : plan OTR + mandat notarial.', '[\"https://images.coinafrique.com/thumb_5721089_uploaded_image1_1768408648.jpg\"]', 'https://tg.coinafrique.com/annonce/villas/vente-maison-a-200-m-de-goudron-a-legbassito-dangbessito-5721089', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-200-m-de-goudron-a-legbassito-dangbessito-5721089\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-200-m-de-goudron-a-legbassito-dangbessito-5721089\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-200-m-de-goudron-a-legbassito-dangbessito-5721089\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(9, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_8', 'Coin-Afrique', '11 000 000 CFA', 11000000, 'Lomé, Togo', 'Maison en vente à Lomé : Agoè Logope Plaisir 2.000 non loin de la pharmacie, espace vie sûr 150 m² soit un quart de lot. Composition : une simple fois (04) quatre, une boutique, une chambre salon wc douche cuisine interne. Document : 3 tampons.', '[]', 'https://tg.coinafrique.com/annonce/villas/vente-maison-4-pieces-agoe-logope-plaisir-2000-5741198', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-4-pieces-agoe-logope-plaisir-2000-5741198\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-4-pieces-agoe-logope-plaisir-2000-5741198\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-4-pieces-agoe-logope-plaisir-2000-5741198\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(10, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_9', 'Coin-Afrique', '50 000 000 CFA', 50000000, 'Lomé, Togo', 'une maison bien positionnée pour toutes activités immobilières à attiegou savoir au niveau d\'un grand carrefour surface presque 1/4 lot papier titre foncier personnel prix 50 millions à débattre visite possible à tout moment', '[\"https://images.coinafrique.com/thumb_5720157_uploaded_image1_1768380274.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/vente-villa-attiegou-5720157', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/vente-villa-attiegou-5720157\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/vente-villa-attiegou-5720157\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/vente-villa-attiegou-5720157\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(11, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_10', 'Coin-Afrique', '4 000 000 CFA', 4000000, 'Lomé, Togo', '1/2 lot a pia (adetikope). demi-lot à adetikope au niveau de pia. plan visé. 01 tampon otr. prix: 4 m discutable', '[\"https://images.coinafrique.com/thumb_5776842_uploaded_image1_1771253555.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-pia-adetikope-5776842', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-pia-adetikope-5776842\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-pia-adetikope-5776842\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-pia-adetikope-5776842\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(12, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_11', 'Coin-Afrique', '200 000 000 CFA', 200000000, 'Lomé, Togo', 'A vendre une immeuble de 10 chambres sur un demi lot avec un plan de titre foncier au bord de goudron à Tossi à 200 millions de francs CFA à revoir légèrement', '[\"https://images.coinafrique.com/thumb_5720965_uploaded_image1_1768403874.jpg\"]', 'https://tg.coinafrique.com/annonce/immeubles/vente-immeuble-au-bord-de-goudron-a-totsi-5720965', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/immeubles/vente-immeuble-au-bord-de-goudron-a-totsi-5720965\", \"location_citation\": \"https://tg.coinafrique.com/annonce/immeubles/vente-immeuble-au-bord-de-goudron-a-totsi-5720965\", \"description_citation\": \"https://tg.coinafrique.com/annonce/immeubles/vente-immeuble-au-bord-de-goudron-a-totsi-5720965\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(13, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_12', 'Coin-Afrique', '18 000 000 CFA', 18000000, 'Lomé, Togo (Quartier: Adidogomè Amadahomè pharmacie izis)', 'A céder d\'une maison Amadahomè pharmacie izis / 1/2 lot soit 300 m². TERRAIN EN VENTE. 1/2 lot en face d\'une rue de 16 m à céder d\'une maison sur 1 lot, très bon emplacement et bien situé, environ 150 m de la grande voie de 50 m. Document : Tampon OTR personnel.', '[\"https://images.coinafrique.com/thumb_5720350_uploaded_image1_1768384009.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-2-a-amadahome-5720350', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-a-amadahome-5720350\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-a-amadahome-5720350\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-a-amadahome-5720350\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(14, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_13', 'Coin-Afrique', '130 000 000 CFA', 130000000, 'Adidogome douane, Lomé, Togo', 'A vendre. 01 lot clôturé en bordure de deux voies (devant et derrière), idéal pour vos projets immobiliers. Papier : titre foncier personnel. Superficie : 600 m².', '[\"https://images.coinafrique.com/thumb_5741628_uploaded_image1_1769412314.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-adidogomee-5740461', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-adidogomee-5740461\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-adidogomee-5740461\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-adidogomee-5740461\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(15, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_14', 'Coin-Afrique', '70 000 000 CFA', 70000000, 'Lomé, Togo', '2 lots et demi collés, soit 1500 m² très bien situés en face d\'une rue de 20 mètres à Segbé, à 800 m du rond‑point douane. Emplacement très stratégique et idéal pour tous projets immobiliers. Document : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_5739011_uploaded_image1_1769254770.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-segbe-5739011', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-segbe-5739011\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-segbe-5739011\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-segbe-5739011\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(16, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_15', 'Coin-Afrique', '450 000 000 CFA', 450000000, 'Lomé, Togo', 'A VENDRE A DJIDJOLE (UN HÔTEL). Un hotel construit sur 04 lots au bord du goudron à DJIDJOLE non loin de la pharmacie du point E. Composé de: 20 chambres, une grande salle de conférence de 400 personnes, salles de réunion, cuisine, bar, dépendance. Titre foncier personnel en cours.', '[\"https://images.coinafrique.com/thumb_5720858_uploaded_image1_1768400687.jpg\"]', 'https://tg.coinafrique.com/annonce/bureaux-et-commerces/vente-hotel-4-lots-a-djidjole-5720858', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/bureaux-et-commerces/vente-hotel-4-lots-a-djidjole-5720858\", \"location_citation\": \"https://tg.coinafrique.com/annonce/bureaux-et-commerces/vente-hotel-4-lots-a-djidjole-5720858\", \"description_citation\": \"https://tg.coinafrique.com/annonce/bureaux-et-commerces/vente-hotel-4-lots-a-djidjole-5720858\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(17, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_16', 'Coin-Afrique', '50 000 000 CFA', 50000000, 'Lomé, Togo', 'TERRAIN A VENDRE A AKATO VIEPE – 2 lots collés, soit 1112 m² en angle de rues et au bord du goudron à AKATO, bon pour tout projet immobilier (bien placé pour station d’essence). Document : Titre Foncier en cours.', '[\"https://images.coinafrique.com/thumb_5720533_uploaded_image1_1768388562.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-a-akato-viepe-5720533', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-a-akato-viepe-5720533\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-a-akato-viepe-5720533\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-a-akato-viepe-5720533\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(18, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_17', 'Coin-Afrique', '5 500 000 CFA', 5500000, 'Lomé, Togo (Legbassito)', 'Un demi (10/30) lot bien propre à réduire de 2 lots est mis en vente dans un quartier en plein développement. Lieu : Legbassito (Kognito non loin de l\'église catholique à 1 km du goudron). Document : titre foncier en cours.', '[]', 'https://tg.coinafrique.com/annonce/terrains/terrain-en-vente-5773526', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-en-vente-5773526\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-en-vente-5773526\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-en-vente-5773526\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(19, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_18', 'Coin-Afrique', '50 000 000 CFA', 50000000, 'Zossimé‑ Nanégbé, Lomé, Togo', 'Terrain 2 lots clôturé Zossimé‑ Nanégbé. 02 lots en déduire sur 04 lots bien positionnés et clôturés pour tout projet immobilier. Superficie : 1200 m². Papier : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_5742008_uploaded_image1_1769426605.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-cloture-zossime-nanegbe-5742008', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-cloture-zossime-nanegbe-5742008\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-cloture-zossime-nanegbe-5742008\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-cloture-zossime-nanegbe-5742008\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(20, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_19', 'Coin-Afrique', '235 000 000 CFA', 235000000, 'Lomé, Togo', 'Villa construite sur demi‑lot à Cacaveli à quelques pas du goudron. Rez-de-chaussée : 1 chambre, salon, cuisine, piscine. R+1 : 4 chambres, salon, terrasse. R+2 : grande terrasse, laverie. Prix 235 millions à revoir légèrement.', '[\"https://images.coinafrique.com/thumb_5739437_uploaded_image1_1769273872.jpg\"]', 'https://tg.coinafrique.com/annonce/villas/vente-villa-duplex-6-pieces-piscine-a-agoe-cacaveli-5739437', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-duplex-6-pieces-piscine-a-agoe-cacaveli-5739437\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-duplex-6-pieces-piscine-a-agoe-cacaveli-5739437\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-duplex-6-pieces-piscine-a-agoe-cacaveli-5739437\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(21, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_20', 'Coin-Afrique', '60 000 000 CFA', 60000000, 'Lomé, Togo (Hedzranawoe aéroport)', 'parcelle de terrain située dans un quartier résidentiel calme et recherché, en angle de rue, offrant une excellente visibilité et une accessibilité optimale. idéal pour villa, résidence familiale ou projet de prestige.', '[\"https://images.coinafrique.com/thumb_5721067_uploaded_image1_1768408175.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-angle-rue-hedzranawoe-aeroport-5721067', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-angle-rue-hedzranawoe-aeroport-5721067\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-angle-rue-hedzranawoe-aeroport-5721067\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-angle-rue-hedzranawoe-aeroport-5721067\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(22, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_21', 'Coin-Afrique', '120 000 000 CFA', 120000000, 'Lomé, Togo', 'parcelle de terrain située dans un quartier résidentiel calme et recherché, en angle de rue, offrant une excellente visibilité et une accessibilité optimale. un cadre idéal pour un projet résidentiel haut standing.', '[\"https://images.coinafrique.com/thumb_5721063_uploaded_image1_1768408082.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-angle-rue-hedzranawoe-aeroport-5721063', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-angle-rue-hedzranawoe-aeroport-5721063\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-angle-rue-hedzranawoe-aeroport-5721063\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-angle-rue-hedzranawoe-aeroport-5721063\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(23, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_22', 'Coin-Afrique', '100 000 000 CFA', 100000000, 'Lomé, Togo', 'Terrain à vendre à Akato Viepe. Deux lots collés, soit 1112 m² en angle de rues et au bord du goudron à Akato, bon pour tout projet immobilier (bien placé pour station d’essence). Document : titre foncier en cours.', '[\"https://images.coinafrique.com/thumb_5720135_uploaded_image1_1768379838.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-akato-viepe-5720135', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-akato-viepe-5720135\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-akato-viepe-5720135\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-2-lots-akato-viepe-5720135\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(24, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_23', 'Coin-Afrique', '4 000 000 CFA', 4000000, 'Lomé, Togo', '1/2 lot à Djagble. Djagble Gbamakope, derrière le C.E.G. Gbamakope. Plan visé + avis favorable. 4 m discutable légèrement.', '[\"https://images.coinafrique.com/thumb_5776837_uploaded_image1_1771253341.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrrain-1-2-lot-djagble-gbamakope-5776837', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrrain-1-2-lot-djagble-gbamakope-5776837\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrrain-1-2-lot-djagble-gbamakope-5776837\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrrain-1-2-lot-djagble-gbamakope-5776837\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(25, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_24', 'Coin-Afrique', '15 000 000 fcfa', 15000000, 'Kara, Togo', 'Avis de vente – villa à Kara. Implantée sur un ancien quart de lot. Surface avantageuse. Bien titré et disponible immédiatement.', '[\"https://images.coinafrique.com/thumb_5782926_uploaded_image1_1771536087.jpg\"]', 'https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(26, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_25', 'Coin-Afrique', '180 000 000 CFA', 180000000, 'Agbavi côté plage, Lomé, Togo', 'Terrain à vendre à agbavi côté plage, à 1km du goudron. 10 lots collés nus soit 60a 25ca très bien situés. Documents : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_4239673_uploaded_image1_1685689717.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(27, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_26', 'Coin-Afrique', '40 000 000 CFA', 40000000, 'Lomé, Togo', 'TERRAIN A VENDRE A KLOBATEMÉ. 2 lots collés disponibles au bord du goudron sur un site initial de 06 lots. Document : Titre Foncier sur 06 lots collés.', '[\"https://images.coinafrique.com/thumb_5721203_uploaded_image1_1768412754.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(28, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_27', 'Coin-Afrique', '25 000 000 CFA', 25000000, 'Lomé, Togo', 'À VENDRE : 02 LOTS COLLÉS À ADIDOGOMÉ GBOMAMÉ. Nous mettons en vente 02 lots collés, solidement clôturés. Document : Titre foncier personnel couvrant les 02 lots. Superficie : 1200 m².', '[\"https://images.coinafrique.com/thumb_5677157_uploaded_image1_1765977395.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
