(33, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_32', 'Coin-Afrique', '35 000 000 CFA', 35000000, 'Lomé, Togo', 'Terrain 200m² à Agoè Démakpoè. Un terrain de surface de 200 m² soit (10 m / 20 m) à déduire d\'une maison face goudron à Agoè Démakpoè. Document : plan visé.', '[\"https://images.coinafrique.com/thumb_4248058_uploaded_image1_1686234189.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35'),
(34, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_33', 'Coin-Afrique', '25 000 000 CFA', 25000000, 'Lomé, Togo', 'Terrain agricole à vendre. 5 hectares à Lilikopé avec titre foncier. Plantés de palmiers à huile, de cocotiers, de manguiers et de bananiers.', '[\"https://images.coinafrique.com/thumb_5724962_uploaded_image1_1768591238.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-agricole-5h-lilikope-5724962', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-agricole-5h-lilikope-5724962\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-agricole-5h-lilikope-5724962\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-agricole-5h-lilikope-5724962\"}', '2026-03-02 01:30:35', '2026-03-02 01:30:35');

