--
-- Structure de la table `igoe_announcements`
--

CREATE TABLE `igoe_announcements` (
  `id` int(11) NOT NULL,
  `external_id` varchar(255) NOT NULL,
  `source` varchar(100) NOT NULL,
  `price` varchar(100) DEFAULT NULL,
  `price_numeric` float DEFAULT NULL,
  `location` varchar(255) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `images` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`images`)),
  `source_url` varchar(500) DEFAULT NULL,
  `citations` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`citations`)),
  `scraped_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Structure de la table `images`
--

CREATE TABLE `images` (
  `id` int(11) NOT NULL,
  `external_id` varchar(255) DEFAULT NULL,
  `source` varchar(100) DEFAULT NULL,
  `url` varchar(1000) NOT NULL,
  `position` int(11) DEFAULT NULL,
  `citations` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`citations`)),
  `created_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

