(1, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_0', 'Coin-Afrique', '26 000 000 CFA', 26000000, 'Lomé, Togo', 'Terrain à Agoè- Vakpossito. A vendre 26 millions très bon terrain en vente un (01) lot clôturé sis à agoè- vakpossito proche du carrefour fish bien positionné pour tout projet immobilier. document : titre foncier prix de vente d\'urgence : 26 millions.', '[\"https://coinafrique-ads-photos.s3.amazonaws.com/photos/6df05fb3-89f.png\", \"https://images.coinafrique.com/thumb_4081859_uploaded_image1_1675665921.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agoe-vakpossito-5783799\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(2, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_1', 'Coin-Afrique', '5 000 000 CFA', 5000000, 'Tsévié - Agbélouve, Lomé, Togo', 'Terrain 5 lots 2971 m² à Tsévié - Agbélouve. Une parcelle stratégique sur 05 lots collés soit (2971 m²) située en trois angles de rue. Très bien positionnée pour tout type de projet immobilier. Position : Tsévié - Agbélouve, à 80 m du goudron. Coût : 5 MILLIONS / lot légèrement discutable. Acte de propriété : Plan visé OTR (Titre foncier en cours).', '[]', 'https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-5-lots-2971m-a-tsevie-agbelouve-5744206\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(3, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_2', 'Coin-Afrique', '4 200 000 CFA', 4200000, 'Lomé, Togo', 'Terrain 1/2 lot à Akébé (Akepe) situé à 800 m du goudron de contournement, bénéficiant d’une voie de 18 m. Superficie de 300 m². À vendre en demi‑lot. Documents disponibles : plan OTR + avis favorable. Prix indiqué : 4 200 000 francs CFA.', '[\"https://images.coinafrique.com/thumb_5739441_uploaded_image1_1769274034.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-2-lot-a-akepe-a-800-m-de-goudron-5739441\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(4, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_3', 'Coin-Afrique', '100 000 000 CFA', 100000000, 'Ahanoukopé marché, Lomé, Togo', 'Terrain 1 lot 625 m² à Ahanoukopé marché. Parcelle bien carrée de 1 lot (625 m²), située à 20 m du goudron (2ᵉ lot). Emplacement stratégique et idéal pour tout projet immobilier ou commercial. Superficie : 625 m². Document : titre foncier personnel. Prix de vente : 100 millions CFA (discutables).', '[\"https://images.coinafrique.com/thumb_5722723_uploaded_image1_1768490644.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-625m-a-ahanoukope-marche-5722806\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
