(25, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_24', 'Coin-Afrique', '15 000 000 fcfa', 15000000, 'Kara, Togo', 'Avis de vente – villa à Kara. Implantée sur un ancien quart de lot. Surface avantageuse. Bien titré et disponible immédiatement.', '[\"https://images.coinafrique.com/thumb_5782926_uploaded_image1_1771536087.jpg\"]', 'https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-villa-kara-5782926\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(26, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_25', 'Coin-Afrique', '180 000 000 CFA', 180000000, 'Agbavi côté plage, Lomé, Togo', 'Terrain à vendre à agbavi côté plage, à 1km du goudron. 10 lots collés nus soit 60a 25ca très bien situés. Documents : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_4239673_uploaded_image1_1685689717.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-a-agbavi-cote-plage-5782408\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(27, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_26', 'Coin-Afrique', '40 000 000 CFA', 40000000, 'Lomé, Togo', 'TERRAIN A VENDRE A KLOBATEMÉ. 2 lots collés disponibles au bord du goudron sur un site initial de 06 lots. Document : Titre Foncier sur 06 lots collés.', '[\"https://images.coinafrique.com/thumb_5721203_uploaded_image1_1768412754.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-a-djable-klobateme-au-bord-du-goudron-5720775\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(28, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_27', 'Coin-Afrique', '25 000 000 CFA', 25000000, 'Lomé, Togo', 'À VENDRE : 02 LOTS COLLÉS À ADIDOGOMÉ GBOMAMÉ. Nous mettons en vente 02 lots collés, solidement clôturés. Document : Titre foncier personnel couvrant les 02 lots. Superficie : 1200 m².', '[\"https://images.coinafrique.com/thumb_5677157_uploaded_image1_1765977395.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-02-lots-colles-a-adidogome-gbomame-5782332\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(29, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_28', 'Coin-Afrique', '30 000 000 CFA', 30000000, 'Lomé, Togo', 'Une maison de location construite sur 1/2 lot (300 m²) à AGOÈ KOSHIGAN non loin du CEG KOSHIGAN. Composée de 5 chambres avec WC et douche interne et terrasse.', '[]', 'https://tg.coinafrique.com/annonce/villas/vente-maison-a-agoe-koshigan-5720843', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-agoe-koshigan-5720843\", \"location_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-agoe-koshigan-5720843\", \"description_citation\": \"https://tg.coinafrique.com/annonce/villas/vente-maison-a-agoe-koshigan-5720843\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(30, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_29', 'Coin-Afrique', '50 000 000 CFA', 50000000, 'Lomé, Togo', 'Mis en vente à agoè koshigan 1 lot ½ soit 800 m² avec un plan de titre foncier personnel bien clôturé. titre de propriété : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_5241847_uploaded_image1_1742473380.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-a-agoe-logope-koshigan-derriere-leglise-catholique-5723267', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-a-agoe-logope-koshigan-derriere-leglise-catholique-5723267\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-a-agoe-logope-koshigan-derriere-leglise-catholique-5723267\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-1-lot-a-agoe-logope-koshigan-derriere-leglise-catholique-5723267\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(31, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_30', 'Coin-Afrique', '45 000 000 CFA', 45000000, 'Lomé, Togo', 'Terrain en vente à Hedzranawoe. 4 lots collés bien situés et positionnés sur 3 voies propice pour tout projet immobilier à Hedzranawoe, pas loin du lycée. Documents : tampon OTR + avis favorable.', '[\"https://images.coinafrique.com/thumb_5723495_uploaded_image1_1768524936.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-04-lots-hedranawoe-lycee-5723495', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-04-lots-hedranawoe-lycee-5723495\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-04-lots-hedranawoe-lycee-5723495\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-04-lots-hedranawoe-lycee-5723495\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(32, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_31', 'Coin-Afrique', '9 000 000 CFA', 9000000, 'Lomé, Togo', 'Terrain 600 m² à noèpe au bord de la 70 m de kovie. A vendre à noèpe, à 2000 mètres de la douane, au bord de la voie de 70 m, 107 lots (64 200 m²). Papier : titre foncier personnel.', '[\"https://images.coinafrique.com/thumb_5723249_uploaded_image1_1768512156.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-600-m-a-noepe-au-bord-de-la-70-m-de-kovie-5723249', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-600-m-a-noepe-au-bord-de-la-70-m-de-kovie-5723249\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-600-m-a-noepe-au-bord-de-la-70-m-de-kovie-5723249\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-600-m-a-noepe-au-bord-de-la-70-m-de-kovie-5723249\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
(33, 'Coin-Afrique_extract-data-2026-02-21-Coin-Afrique_32', 'Coin-Afrique', '35 000 000 CFA', 35000000, 'Lomé, Togo', 'Terrain 200m² à Agoè Démakpoè. Un terrain de surface de 200 m² soit (10 m / 20 m) à déduire d\'une maison face goudron à Agoè Démakpoè. Document : plan visé.', '[\"https://images.coinafrique.com/thumb_4248058_uploaded_image1_1686234189.jpg\"]', 'https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802', '{\"price_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\", \"location_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\", \"description_citation\": \"https://tg.coinafrique.com/annonce/terrains/terrain-200m-a-agoe-demakpoe-5722802\"}', '2026-03-02 01:21:03', '2026-03-02 01:21:03'),
